const standings = ($json.standings || []);
const top10 = standings.sort((a,b)=>(b.points||0)-(a.points||0)).slice(0,10)
  .map(t => ({name: t.teamName?.default || t.teamAbbrev?.default || 'Team', points: t.points||0, wins: t.wins||0, losses: t.losses||0, streak: t.streakCode||''}));
const hot = top10.filter(t => t.streak.startsWith('W') && parseInt(t.streak.slice(1))>=3);
const ctx = 'NHL standings top 10:\n' + top10.map(t=>`${t.name}: ${t.points}pts ${t.wins}W-${t.losses}L${t.streak?' streak:'+t.streak:''}`).join('\n') + '\n\nHot teams: ' + (hot.map(t=>t.name+' ('+t.streak+')').join(', ')||'none');
return [{ json: { context: ctx, hotTeams: hot } }]
, perfContext: (() => { try { const body = $('Read Performance Insights').first().json.Body; const ins = JSON.parse(body); const t = ins.insights && ins.insights['thehockeyanalytics.com']; return t && t.suggested_keywords ? 'High-performing topics: ' + t.suggested_keywords.join(', ') : ''; } catch(e) { return ''; } })()
};

const body = $input.item.json;
let arr = [];
try {
  const txt = body.choices?.[0]?.message?.content || '[]';
  const m = txt.match(/\[[\s\S]*\]/);
  arr = JSON.parse(m ? m[0] : txt);
} catch(e) { arr = []; }
arr = arr.filter(x => x.score >= 7).slice(0,20);
if (arr.length === 0) arr = [
  {keyword:'NHL playoff analytics 2026',score:9,rationale:'timely'},
  {keyword:'expected goals hockey explained',score:9,rationale:'evergreen'},
  {keyword:'Corsi stat beginner guide',score:8,rationale:'high volume'},
  {keyword:'advanced defensive metrics NHL',score:8,rationale:'analytical'},
  {keyword:'power play efficiency analytics',score:7,rationale:'specific'}
];
return arr.map(x => ({ json: {keyword:x.keyword, score:x.score, rationale:x.rationale} }));

const items = $input.all();
const keywords = items.map(i => ({keyword:i.json.keyword, score:i.json.score, rationale:i.json.rationale||''}));
return [{ json: { keywords, count: keywords.length, savedAt: new Date().toISOString() } }];

const prev = $('Aggregate THA Keywords').item.json;
const kws = prev.keywords || [];
const top5 = kws.slice(0,5);
const lines = top5.map((k,i)=>`${i+1}. <b>${k.keyword}</b> (${k.score}/10)`).join('
');
const text = `🏒 <b>THA Keyword Research – ${prev.count} nyckelord</b>

Top 5 idag:
${lines}

